        '+1234567890',
        '123456',
        '127.0.0.1',
        'test-agent',
        undefined,
        undefined
      );
      expect(mockRes.cookie).toHaveBeenCalledWith(
        'refresh_token',
        'refresh',
        expect.any(Object),
      );
      expect(result.accessToken).toBe('access');
