import { Test, TestingModule } from '@nestjs/testing';
import { EmployersService } from './employers.service';
import { PrismaService } from '../../infrastructure/database/prisma.service';
import { NotFoundException, ConflictException } from '@nestjs/common';

describe('EmployersService', () => {
  let service: EmployersService;
  let prismaService: jest.Mocked<PrismaService>;

  beforeEach(async () => {
    const mockPrismaService = {
      employerProfile: {
        findUnique: jest.fn(),
        upsert: jest.fn(),
      },
      department: {
        findFirst: jest.fn(),
        create: jest.fn(),
        findMany: jest.fn(),
      },
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        EmployersService,
        { provide: PrismaService, useValue: mockPrismaService },
      ],
    }).compile();

    service = module.get<EmployersService>(EmployersService);
    prismaService = module.get(PrismaService);
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('getProfile', () => {
    it('should return profile if found', async () => {
      const mockProfile = { id: '1', userId: 'user1' };
      (prismaService.employerProfile.findUnique as jest.Mock).mockResolvedValue(
        mockProfile,
      );

      const result = await service.getProfile('user1');
      expect(result).toEqual(mockProfile);
    });

    it('should throw NotFoundException if profile not found', async () => {
      (prismaService.employerProfile.findUnique as jest.Mock).mockResolvedValue(
        null,
      );
      await expect(service.getProfile('user1')).rejects.toThrow(
        NotFoundException,
      );
    });
  });

  describe('updateProfile', () => {
    it('should upsert profile', async () => {
      const mockProfile = { id: '1', userId: 'user1', companyName: 'New Corp' };
      (prismaService.employerProfile.upsert as jest.Mock).mockResolvedValue(
        mockProfile,
      );

      const result = await service.updateProfile('user1', {
        companyName: 'New Corp',
      });
      expect(result).toEqual(mockProfile);
      expect(prismaService.employerProfile.upsert).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { userId: 'user1' },
        }),
      );
    });
  });

  describe('addDepartment', () => {
    it('should throw NotFoundException if employer profile does not exist', async () => {
      (prismaService.employerProfile.findUnique as jest.Mock).mockResolvedValue(
        null,
      );
      await expect(
        service.addDepartment('user1', { name: 'HR' }),
      ).rejects.toThrow(NotFoundException);
    });

    it('should throw ConflictException if department already exists', async () => {
      (prismaService.employerProfile.findUnique as jest.Mock).mockResolvedValue(
        { id: 'emp1' },
      );
      (prismaService.department.findFirst as jest.Mock).mockResolvedValue({
        id: 'dep1',
      });

      await expect(
        service.addDepartment('user1', { name: 'HR' }),
      ).rejects.toThrow(ConflictException);
    });

    it('should create department', async () => {
      (prismaService.employerProfile.findUnique as jest.Mock).mockResolvedValue(
        { id: 'emp1' },
      );
      (prismaService.department.findFirst as jest.Mock).mockResolvedValue(null);

      const newDep = { id: 'dep2', name: 'HR', employerId: 'emp1' };
      (prismaService.department.create as jest.Mock).mockResolvedValue(newDep);

      const result = await service.addDepartment('user1', { name: 'HR' });
      expect(result).toEqual(newDep);
      expect(prismaService.department.create).toHaveBeenCalledWith(
        expect.objectContaining({
          data: expect.objectContaining({ name: 'HR', employerId: 'emp1' }),
        }),
      );
    });
  });
});

import {
  Injectable,
  NotFoundException,
  ConflictException,
} from '@nestjs/common';
import { PrismaService } from '../../infrastructure/database/prisma.service';
import { UpdateEmployerProfileDto } from './dto/update-employer-profile.dto';
import { AddDepartmentDto } from './dto/add-department.dto';

@Injectable()
export class EmployersService {
  constructor(private readonly prisma: PrismaService) {}

  async getProfile(userId: string) {
    const profile = await this.prisma.employerProfile.findUnique({
      where: { userId },
      include: {
        departments: true,
      },
    });

    if (!profile) {
      throw new NotFoundException('Employer profile not found');
    }

    return profile;
  }

  async updateProfile(userId: string, updateDto: UpdateEmployerProfileDto) {
    return this.prisma.employerProfile.upsert({
      where: { userId },
      update: updateDto as any,
      create: {
        userId,
        companyName: updateDto.companyName || 'My Company',
        industry: updateDto.industry || 'Other',
        location: updateDto.location ? (updateDto.location as any) : {},
      },
      include: {
        departments: true,
      },
    });
  }

  async addDepartment(userId: string, departmentDto: AddDepartmentDto) {
    const profile = await this.prisma.employerProfile.findUnique({
      where: { userId },
    });
    if (!profile) {
      throw new NotFoundException('Employer profile not found');
    }

    const existingDepartment = await this.prisma.department.findFirst({
      where: {
        employerId: profile.id,
        name: departmentDto.name,
      },
    });

    if (existingDepartment) {
      throw new ConflictException('Department already exists');
    }

    return this.prisma.department.create({
      data: {
        employerId: profile.id,
        name: departmentDto.name,
        headCount: 0,
      },
    });
  }

  async getDepartments(userId: string) {
    const profile = await this.prisma.employerProfile.findUnique({
      where: { userId },
    });
    if (!profile) {
      throw new NotFoundException('Employer profile not found');
    }

    return this.prisma.department.findMany({
      where: { employerId: profile.id },
    });
  }

  async getDashboardStats(userId: string) {
    const profile = await this.prisma.employerProfile.findUnique({
      where: { userId },
      include: {
        _count: {
          select: {
            jobs: true,
            departments: true,
          },
        },
        jobs: {
          select: {
            _count: {
              select: {
                applications: true,
                shifts: true,
              },
            },
          },
        },
      },
    });

    if (!profile) {
      throw new NotFoundException('Employer profile not found');
    }

    const activeJobsCount = profile._count.jobs;
    let totalApplications = 0;
    let totalShifts = 0;

    for (const job of profile.jobs) {
      totalApplications += job._count.applications;
      totalShifts += job._count.shifts;
    }

    const completion = this.calculateProfileCompletion(profile);

    return {
      activeJobs: activeJobsCount,
      totalApplications,
      totalShifts,
      totalDepartments: profile._count.departments,
      profileCompletion: completion,
      rating: profile.rating,
      totalSpent: 0, // Placeholder
    };
  }

  private calculateProfileCompletion(profile: any): number {
    let score = 0;
    const totalFields = 4;

    if (profile.companyName) score += 1;
    if (profile.industry) score += 1;
    if (profile.logoUrl) score += 1;
    if (profile.website) score += 1;

    return Math.round((score / totalFields) * 100);
  }
}

import { Controller, Get, VERSION_NEUTRAL } from '@nestjs/common';
import { ApiTags, ApiOperation } from '@nestjs/swagger';
import {
  HealthCheckService,
  HealthCheck,
  PrismaHealthIndicator,
  HealthCheckResult,
} from '@nestjs/terminus';
import { Public } from '../../shared/decorators/public.decorator';
import { RedisService } from '../../infrastructure/redis/redis.service';
import { HealthIndicatorResult } from '@nestjs/terminus';
import { Injectable } from '@nestjs/common';

@Injectable()
export class RedisHealthIndicator {
  constructor(private readonly redisService: RedisService) {}

  async isHealthy(key: string): Promise<HealthIndicatorResult> {
    const isAlive = await this.redisService.ping();
    if (!isAlive) {
      throw new Error('Redis is not responding');
    }
    return { [key]: { status: 'up' } };
  }
}

import { PrismaService } from '../../infrastructure/database/prisma.service';

@ApiTags('Health')
@Controller({ path: 'health', version: VERSION_NEUTRAL })
export class HealthController {
  constructor(
    private readonly health: HealthCheckService,
    private readonly prismaHealth: PrismaHealthIndicator,
    private readonly redisHealth: RedisHealthIndicator,
    private readonly prisma: PrismaService,
  ) {}

  @Get('live')
  @Public()
  @ApiOperation({ summary: 'Kubernetes liveness probe' })
  liveness(): { status: string; timestamp: string } {
    return { status: 'ok', timestamp: new Date().toISOString() };
  }

  @Get('ready')
  @Public()
  @HealthCheck()
  @ApiOperation({
    summary: 'Kubernetes readiness probe — checks all dependencies',
  })
  async readiness(): Promise<HealthCheckResult> {
    return this.health.check([
      async () => this.prismaHealth.pingCheck('database', this.prisma),
      async () => this.redisHealth.isHealthy('redis'),
    ]);
  }
}

