        page: 2,
        limit: 5,
      });

      expect(prisma.job.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          skip: 5,
          take: 5,
        }),
      );
    });
  });

  describe('getJobById', () => {
    it('should throw NotFoundException if job not found', async () => {
      prisma.job.findUnique = jest.fn().mockResolvedValue(null);
