import {
  Injectable,
  NotFoundException,
  ConflictException,
} from '@nestjs/common';
import { PrismaService } from '../../infrastructure/database/prisma.service';
import { UpdateWorkerProfileDto } from './dto/update-worker-profile.dto';
import { AddWorkerSkillDto } from './dto/add-worker-skill.dto';

@Injectable()
export class WorkersService {
  constructor(private readonly prisma: PrismaService) {}

  async getProfile(userId: string) {
    const profile = await this.prisma.workerProfile.findUnique({
      where: { userId },
      include: {
        skills: {
          include: {
            skill: true,
          },
        },
        certifications: true,
      },
    });

    if (!profile) {
      throw new NotFoundException('Worker profile not found');
    }

    return profile;
  }

  async updateProfile(userId: string, updateDto: UpdateWorkerProfileDto) {
    return this.prisma.workerProfile.upsert({
      where: { userId },
      update: updateDto as any,
      create: {
        userId,
        firstName: updateDto.firstName || 'Worker',
        lastName: updateDto.lastName || 'Profile',
        bio: updateDto.bio || null,
        location: updateDto.location ? (updateDto.location as any) : {},
        // Defaults handles the rest
      },
      include: {
        skills: {
          include: { skill: true },
        },
      },
    });
  }

  async addSkill(userId: string, skillDto: AddWorkerSkillDto) {
    const profile = await this.prisma.workerProfile.findUnique({
      where: { userId },
    });
    if (!profile) {
      throw new NotFoundException('Worker profile not found');
    }

    // Upsert skill in the global skills table
    const skill = await this.prisma.skill.upsert({
      where: { name: skillDto.skillName },
      update: {},
      create: {
        name: skillDto.skillName,
        category: skillDto.category,
      },
    });

    // Check if worker already has this skill
    const existingSkill = await this.prisma.workerSkill.findUnique({
      where: {
        workerId_skillId: {
          workerId: profile.id,
          skillId: skill.id,
        },
      },
    });

    if (existingSkill) {
      throw new ConflictException('Worker already has this skill');
    }

    // Link skill to worker
    return this.prisma.workerSkill.create({
      data: {
        workerId: profile.id,
        skillId: skill.id,
        yearsExp: skillDto.yearsExp,
        proficiency: skillDto.proficiency,
      },
      include: {
        skill: true,
      },
    });
  }

  async removeSkill(userId: string, skillId: string) {
    const profile = await this.prisma.workerProfile.findUnique({
      where: { userId },
    });
    if (!profile) {
      throw new NotFoundException('Worker profile not found');
    }

    return this.prisma.workerSkill.delete({
      where: {
        workerId_skillId: {
          workerId: profile.id,
          skillId: skillId,
        },
      },
    });
  }

  async getDashboardStats(userId: string) {
    const profile = await this.prisma.workerProfile.findUnique({
      where: { userId },
      include: {
        _count: {
          select: {
            applications: true,
            shifts: true,
          },
        },
      },
    });

    if (!profile) {
      throw new NotFoundException('Worker profile not found');
    }

    const completion = this.calculateProfileCompletion(profile);

    return {
      totalEarnings: 0, // Placeholder until payments module is linked
      activeApplications: profile._count.applications,
      completedShifts: profile._count.shifts,
      profileCompletion: completion,
      rating: profile.rating,
    };
  }

  private calculateProfileCompletion(profile: any): number {
    let score = 0;
    const totalFields = 5;

    if (profile.firstName && profile.lastName) score += 1;
    if (profile.bio) score += 1;
    if (profile.avatarUrl) score += 1;
    if (profile.experienceYears > 0) score += 1;
    if (profile.hourlyRate) score += 1;

    return Math.round((score / totalFields) * 100);
  }
}

import { ExecutionContext } from '@nestjs/common';
import { CurrentUser } from './current-user.decorator';
import { RequirePermissions, PERMISSIONS_KEY } from './permissions.decorator';
import { UserRole, JwtPayload } from '@shiftly/shared-types';
import { Public, IS_PUBLIC_KEY } from './public.decorator';
import { Roles, ROLES_KEY } from './roles.decorator';

// Helper to get custom parameter decorators
import { ROUTE_ARGS_METADATA } from '@nestjs/common/constants';

function getParamDecoratorFactory(decorator: Function, ...argsToPass: any[]) {
  class Test {
    public test(@decorator(...argsToPass) value: any) {}
  }
  const args = Reflect.getMetadata(ROUTE_ARGS_METADATA, Test, 'test');
  return args[Object.keys(args)[0]].factory;
}

describe('Decorators', () => {
  describe('CurrentUser Decorator', () => {
    it('should extract the whole user object if no data is provided', () => {
      const factory = getParamDecoratorFactory(CurrentUser);

      const mockUser = { sub: '123', email: 'test@test.com' };
      const ctx = {
        switchToHttp: () => ({
          getRequest: () => ({ user: mockUser }),
        }),
      } as unknown as ExecutionContext;

      const result = factory(null, ctx);
      expect(result).toBe(mockUser);
    });

    it('should extract a specific field if data is provided', () => {
      const factory = getParamDecoratorFactory(CurrentUser, 'email');

      const mockUser = { sub: '123', email: 'test@test.com' };
      const ctx = {
        switchToHttp: () => ({
          getRequest: () => ({ user: mockUser }),
        }),
      } as unknown as ExecutionContext;

      const result = factory('email', ctx);
      expect(result).toBe('test@test.com');
    });
  });

  describe('Permissions', () => {
    it('should set permissions metadata', () => {
      class TestClass {
        @RequirePermissions('READ_USER')
        testMethod() {}
      }

      const permissions = Reflect.getMetadata(
        PERMISSIONS_KEY,
        TestClass.prototype.testMethod,
      );
      expect(permissions).toEqual(['READ_USER']);
    });
  });

  describe('Public', () => {
    it('should set public metadata', () => {
      class TestClass {
        @Public()
        testMethod() {}
      }

      const isPublic = Reflect.getMetadata(
        IS_PUBLIC_KEY,
        TestClass.prototype.testMethod,
      );
      expect(isPublic).toBe(true);
    });
  });

  describe('Roles', () => {
    it('should set roles metadata', () => {
      class TestClass {
        @Roles('ADMIN', 'WORKER')
        testMethod() {}
      }

      const roles = Reflect.getMetadata(
        ROLES_KEY,
        TestClass.prototype.testMethod,
      );
      expect(roles).toEqual(['ADMIN', 'WORKER']);
    });
  });
});

