        method: 'GET',
        url: '/test',
        headers: {},
      };
      mockArgumentsHost = {
        switchToHttp: jest.fn().mockReturnValue({
          getResponse: () => mockResponse,
          getRequest: () => mockRequest,
        }),
      } as unknown as ArgumentsHost;

      process.env.NODE_ENV = 'development';
    });

    it('should handle standard HttpException with string response', () => {
      const exception = new HttpException('Forbidden', HttpStatus.FORBIDDEN);
      filter.catch(exception, mockArgumentsHost);

      expect(mockResponse.status).toHaveBeenCalledWith(HttpStatus.FORBIDDEN);
      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          error: expect.objectContaining({
            statusCode: HttpStatus.FORBIDDEN,
            message: 'Forbidden',
            code: ERROR_CODES.INTERNAL_SERVER_ERROR, // Default from initialization since it's a string response
          }),
        }),
      );
      expect(mockLogger.warn).toHaveBeenCalled();
    });

    it('should handle standard HttpException with object response', () => {
      const exception = new HttpException(
        {
          message: 'Invalid input',
          error: 'BAD_REQUEST',
        },
        HttpStatus.BAD_REQUEST,
      );

      filter.catch(exception, mockArgumentsHost);

      expect(mockResponse.status).toHaveBeenCalledWith(HttpStatus.BAD_REQUEST);
      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: 'Invalid input',
            code: 'BAD_REQUEST',
          }),
        }),
      );
      expect(mockLogger.warn).toHaveBeenCalled();
    });

    it('should handle class-validator array of messages', () => {
      const exception = new HttpException(
        {
          message: ['email must be a valid email', 'password is too short'],
        },
        HttpStatus.BAD_REQUEST,
      );

      filter.catch(exception, mockArgumentsHost);

      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: 'Validation failed',
            code: ERROR_CODES.VALIDATION_ERROR,
            details: [
              { field: 'email', message: 'email must be a valid email' },
              { field: 'password', message: 'password is too short' },
            ],
          }),
        }),
      );
    });

    it('should handle unknown Error and log it as 500', () => {
      const error = new Error('Database connection failed');
      filter.catch(error, mockArgumentsHost);

      expect(mockResponse.status).toHaveBeenCalledWith(
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: 'Database connection failed',
            code: ERROR_CODES.INTERNAL_SERVER_ERROR,
          }),
        }),
      );
      expect(mockLogger.error).toHaveBeenCalledTimes(2); // One for Unhandled exception, one for 500 error
    });

    it('should hide error details in production for 500', () => {
      process.env.NODE_ENV = 'production';
      const error = new Error('Secret database credentials');

      filter.catch(error, mockArgumentsHost);

      expect(mockResponse.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: 'An unexpected error occurred. Please try again.',
          }),
        }),
      );
    });
  });
});

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
  Logger,
} from '@nestjs/common';
import { Request, Response } from 'express';
import { v4 as uuidv4 } from 'uuid';
import { ERROR_CODES } from '@shiftly/shared-constants';

interface ErrorDetail {
  field?: string;
  message: string;
}

interface ErrorResponse {
  success: false;
  error: {
    code: string;
    message: string;
    details: ErrorDetail[];
    statusCode: number;
  };
  meta: {
    timestamp: string;
    requestId: string;
  };
}

@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  constructor(private readonly logger: Logger) {}

  catch(exception: unknown, host: ArgumentsHost): void {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    const requestId = (request.headers['x-request-id'] as string) ?? uuidv4();
    let statusCode = HttpStatus.INTERNAL_SERVER_ERROR;
    let errorCode: string = ERROR_CODES.INTERNAL_SERVER_ERROR;
    let message = 'An unexpected error occurred. Please try again.';
    let details: ErrorDetail[] = [];

    if (exception instanceof HttpException) {
      statusCode = exception.getStatus();
      const exceptionResponse = exception.getResponse();

      if (typeof exceptionResponse === 'string') {
        message = exceptionResponse;
      } else if (
        typeof exceptionResponse === 'object' &&
        exceptionResponse !== null
      ) {
        const resp = exceptionResponse as Record<string, unknown>;
        message = (resp['message'] as string) ?? message;
        errorCode =
          (resp['error'] as string) ?? this.getErrorCodeFromStatus(statusCode);

        // Handle class-validator ValidationPipe errors
        if (Array.isArray(resp['message'])) {
          message = 'Validation failed';
          errorCode = ERROR_CODES.VALIDATION_ERROR;
          details = (resp['message'] as string[]).map((msg) => {
            const parts = msg.split(' ');
            const field = parts[0];
            return { field, message: msg };
          });
        }
      }
    } else if (exception instanceof Error) {
      // Log unexpected errors fully
      this.logger.error(
        `Unhandled exception: ${exception.message}`,
        exception.stack,
        'GlobalExceptionFilter',
      );

      // In production, don't expose internal error details
      if (process.env.NODE_ENV === 'production') {
        message = 'An unexpected error occurred. Please try again.';
      } else {
        message = exception.message;
      }
    }

    // Log all 5xx errors
    if (statusCode >= 500) {
      this.logger.error(
        `[${statusCode}] ${request.method} ${request.url} - ${message}`,
        exception instanceof Error ? exception.stack : undefined,
        'GlobalExceptionFilter',
      );
    } else if (statusCode >= 400) {
      this.logger.warn(
        `[${statusCode}] ${request.method} ${request.url} - ${message}`,
        'GlobalExceptionFilter',
      );
    }

    const errorResponse: ErrorResponse = {
      success: false,
      error: {
        code: errorCode,
        message,
        details,
        statusCode,
      },
      meta: {
        timestamp: new Date().toISOString(),
        requestId,
      },
    };

    response
      .status(statusCode)
      .set('X-Request-ID', requestId)
      .json(errorResponse);
  }

  private getErrorCodeFromStatus(status: number): string {
    switch (status) {
      case 400:
        return ERROR_CODES.VALIDATION_ERROR;
      case 401:
        return ERROR_CODES.UNAUTHORIZED;
      case 403:
        return ERROR_CODES.FORBIDDEN;
      case 404:
        return ERROR_CODES.NOT_FOUND;
      case 409:
        return ERROR_CODES.CONFLICT;
      case 429:
        return ERROR_CODES.RATE_LIMIT_EXCEEDED;
      default:
        return ERROR_CODES.INTERNAL_SERVER_ERROR;
    }
  }
}

import { ExecutionContext, UnauthorizedException } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtAuthGuard } from './jwt-auth.guard';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';

describe('JwtAuthGuard', () => {
  let guard: JwtAuthGuard;
  let reflector: Reflector;

  beforeEach(() => {
    reflector = new Reflector();
    guard = new JwtAuthGuard(reflector);
  });

  describe('canActivate', () => {
    it('should return true if route is public', () => {
      jest.spyOn(reflector, 'getAllAndOverride').mockReturnValue(true);
      const context = {
        getHandler: jest.fn(),
        getClass: jest.fn(),
      } as unknown as ExecutionContext;

      expect(guard.canActivate(context)).toBe(true);
      expect(reflector.getAllAndOverride).toHaveBeenCalledWith(IS_PUBLIC_KEY, [
        context.getHandler(),
        context.getClass(),
      ]);
    });

    it('should call super.canActivate if route is not public', () => {
      jest.spyOn(reflector, 'getAllAndOverride').mockReturnValue(false);
      const context = {
        getHandler: jest.fn(),
        getClass: jest.fn(),
      } as unknown as ExecutionContext;

      // Mock the super.canActivate method
      const superCanActivateSpy = jest
        .spyOn(Object.getPrototypeOf(guard), 'canActivate')
        .mockReturnValue(true);

      const result = guard.canActivate(context);
      expect(result).toBe(true);
      expect(superCanActivateSpy).toHaveBeenCalledWith(context);
    });
  });

  describe('handleRequest', () => {
    it('should return user if no error and user exists', () => {
      const mockUser = { id: 1 };
      const result = guard.handleRequest(null as unknown as Error, mockUser);
      expect(result).toBe(mockUser);
    });

    it('should throw error if error exists', () => {
      const error = new Error('test error');
      expect(() => guard.handleRequest(error, null)).toThrow(error);
    });

    it('should throw UnauthorizedException if no user', () => {
      expect(() => guard.handleRequest(new Error('test'), null)).toThrow(
        'test',
      );
      expect(() => guard.handleRequest(null as unknown as Error, null)).toThrow(
        'Authentication required. Please log in.',
      );
    });
  });
});

